mapper.select:
SELECT 
FROM t_user_question uq
LEFT JOIN t_question q ON uq.question_id = q.id
WHERE uq.user_id = #{userId}
ORDER BY uq.create_time DESC
LIMIT #{limit}

mapper.update:
UPDATE t_user_question
is_correct = #{isCorrect}, is_wrong_book = #{isWrongBook}, user_answer = #{userAnswer}, attempt_count = #{attemptCount},
WHERE id = #{id}
